import{_ as o}from"./plugin-vue_export-helper-c27b6911.js";import{r as s,o as r,c as l,d as e,f as n,b as a,w as t}from"./app-e82c0db3.js";const c="/background.jpg",d="/assets/peng-55e81203.jpg",f="/assets/wang-c7f22612.jpg",h="/assets/Su-38b9e7e2.jpg";const u={},m=e("figure",null,[e("img",{src:c,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),g={id:"challenges-in-artificial-intelligence-and-cybersecurity",tabindex:"-1"},y=e("a",{class:"header-anchor",href:"#challenges-in-artificial-intelligence-and-cybersecurity","aria-hidden":"true"},"#",-1),p=e("div",{style:{"font-family":"Times New Roman",color:"black"}},[e("p",{style:{"text-align":"center","font-family":"Times New Roman","font-size":"20px"}},[n("Peng Shi"),e("br"),n("School of Electrical and Mechanical Engineering"),e("br"),n("University of Adelaide, Australia"),e("br"),n("Peng.shi@adelaide.edu.au")]),n(),e("br"),e("p",{style:{"text-align":"justify","font-family":"Times New Roman","font-size":"20px"}},[e("b",null,"Abstract:"),n(" Artificial intelligence (AI) is now one of the most popular and fundamental areas, and has found its practical applications in many fields, such as autonomous and robotic systems, manufacturing systems, cyber-physical systems, communication systems, image and pattern recognitions, etc. AI has been extensively studied in the past decades. There is no doubt that AI has been and will continue playing a big role in our daily life and real world applications. This talk will present some challenges facing to AI, and issues in cybersecurity. ")]),e("br"),e("p",{style:{"text-align":"justify","font-family":"Times New Roman","font-size":"20px"}},[e("img",{src:d,align:"left",width:"110",heigh:"120",hspace:"5",vspace:"8",style:{"padding-top":"10px","padding-right":"10px"}}),n(),e("b",null,"Peng Shi"),n(" received the PhD degree in Electrical Engineering from the University of Newcastle, Australia in 1994. He was awarded the higher doctorate -- the Doctor of Science degree from the University of Glamorgan, UK in 2006, and the Doctor of Engineering degree from the University of Adelaide, Australia in 2015. He is now a Distinguished Professor at the School of Electrical and Mechanical Engineering, and the Director of Advanced Unmanned Systems Laboratory, at The University of Adelaide, Australia. His research interests include systems and control theory and applications to autonomous and robotic systems, cyber-physical systems, and multi-agent systems. He received the Life-time Achievement Award from the International Engineering and Technology Institute in 2023, the Meritorious Service Award from IEEE Systems, Man and Cybernetics (SMC) Society in 2023, the MA Sargent Medal Award from Engineers Australia in 2022; the Life-time Achiever Leaderboard and Field Leader Recognition from The AUSTRALIAN Research Review from 2019-2023, and the Highly Cited Researcher Acknowledgement from Clarivate Analystics 2014-2023. Currently he serves as the Editor-in-Chief of IEEE Transactions on Cybernetics, a Senior Editor of IEEE Access, and an associate editor for several journals, including Information Sciences, IEEE Transactions on Artificial Intelligence and Automatica. His professional services also include as the President of the International Academy for Systems and Cybernetic Sciences (2021--), the Vice President of IEEE SMC Society (2021-2022), and IEEE SMC Society Distinguished Lecturer (2020--). He is a Fellow of IEEE, IET, IETI, IEAust, CAA, and a Member of the Academy of Europe.")])],-1),E={id:"evolutionary-framework-for-t-closeness-anonymization",tabindex:"-1"},A=e("a",{class:"header-anchor",href:"#evolutionary-framework-for-t-closeness-anonymization","aria-hidden":"true"},"#",-1),b=e("div",{style:{"font-family":"Times New Roman",color:"black"}},[e("p",{style:{"text-align":"center","font-family":"Times New Roman","font-size":"20px"}},[n("Hua Wang"),e("br"),n("Institute for Sustainable Industries and Liveable Cities (ISILC)"),e("br"),n("Victoria University, Australia")]),n(),e("br"),e("p",{style:{"text-align":"justify","font-family":"Times New Roman","font-size":"20px"}},[e("b",null,"Abstract:"),n(" Data anonymization is a fundamental and practical privacy preserving data publication (PPDP) method, while searching for the optimal anonymization scheme using traditional methods has been proven to be NP-hard. Some recent studies have introduced genetic algorithms (GA) into data anonymization to address this issue, revealing potential solutions. However, the discussions are restricted to a few privacy protection models and evolutionary algorithms (EAs). This talk extends this field by introducing differential evolution (DE) for the first time to optimize data anonymization schemes under the constraints of the t-closeness privacy model. To further enhance the algorithm’s performance, we design a two-layer evolutionary framework (TLEF) that effectively explores optimal solutions by leveraging the unique properties of both GA and DE in a balanced manner. Experimental evaluations conducted on 16 test datasets highlight the advantages of DE in addressing optimal t-closeness anonymization and validate the effectiveness of the TLEF. ")]),e("br"),e("p",{style:{"text-align":"justify","font-family":"Times New Roman","font-size":"20px"}},[e("img",{src:f,align:"left",width:"110",heigh:"120",hspace:"5",vspace:"8",style:{"padding-top":"10px","padding-right":"10px"}}),n(),e("b",null,"Hua Wang"),n(" is now a full time professor in the Institute for Sustainable Industries and Liveable Cities (ISILC) at Victoria University. Hua carries out research on machine learning and data analysis, with a particular focus on data mining, artificial intelligence, deep learning, big data, privacy preserving, access control and cyber security. As a Chief Investigator, Hua has successfully received ten large Australian Research Council (ARC) grants including seven discovery grants and three linkage grants with AU$6.0M since 2006. He is also a successor for international grants such as two grants from Japan Society for the Promotion of Science (JSPS), one German–Australian grant (DAAD), one Norwegian government grant, three grants from Hong Kong and two from China.")]),e("p",{style:{"text-align":"justify","font-family":"Times New Roman","font-size":"20px"}},"Hua has published 400 refereed scholar papers with 12000+ citations, including 81 Q1 (ERA2018 ranked) Journal papers in machine learning, cyber security, Artificial Intelligence, privacy preserving and data analysis. Representative publications are on:"),e("ul",{style:{"text-align":"justify","font-family":"Times New Roman","font-size":"18px",color:"black"}},[e("li",null,"ACM Transactions on Internet Technology"),e("li",null,"ACM Transactions on Information Systems"),e("li",null,"ACM Transactions on Knowledge Discovery from Data"),e("li",null,"IEEE Transactions on Dependable and Secure Computing"),e("li",null,"IEEE Transactions on Knowledge and Data Engineering"),e("li",null,"IEEE Transactions on Automation Science and Engineering"),e("li",null,"IEEE Transactions on Evolutionary Computation"),e("li",null,"IEEE Transactions on Services Computing"),e("li",null,"Proceedings of ACL, AAAI, CIKM, ICDE, ICDM and PAKDD")]),e("p",{style:{"text-align":"justify","font-family":"Times New Roman","font-size":"20px"}},[n("Hua's h-index is 65 based on Google Scholar website. As a principal supervisor, he currently has 14 PhD students at VU."),e("br"),n("Hua has been appointed as a College of Expert by the ARC since 2021, and has already been an ARC reviewer since 2009. He reviews various proposals each year for ARC DP, LP, DECRA, LIEF. Hua is Editor-in-Chief, Featured Journals, European Alliance for Innovation (EAI) Transactions on Scalable Information Systems, and also editor for PLOS ONE and World Wide Web Journal, Springer. He is involved in many prestigious international conferences such as PC members (ICDE2022-24, AAAI2019, IJCAR2022, 23) and chairs for the International Conference on Web Information Systems Engineering (WISE) 2015-2018."),e("br"),n("Hua is the discipline leader of technology in engineering and science at VU, and a director of Oceania Cyber Security Centre (OCSC) consisting of eight Victorian universities with substantial support from the Victorian government, with engagement of industry. He is working as a committee member for:")]),e("ul",{style:{"text-align":"justify","font-family":"Times New Roman","font-size":"18px",color:"black"}},[e("li",null,"IEEE Blockchain Standards group"),e("li",null,"IEEE COMSOC Project 1912 Privacy and Security Architecture for Consumer Wireless Devices Working Group"),e("li",null,"Japan Society for the Promotion of Science Alumni Association in Australia (JSPSAAA)"),e("li",null,"Data61 University Planning Committee.")]),e("p",{style:{"text-align":"justify","font-family":"Times New Roman","font-size":"20px"}},"Hua is served as lots of professional editors such as:"),e("ol",{style:{"text-align":"justify","font-family":"Times New Roman","font-size":"18px",color:"black"}},[e("li",null,"Editor of IEEE Transactions of Cybernetic;"),e("li",null,"Editor of IEEE Transactions of on Technology and Society;"),e("li",null,"Editor-in-Chief of EAI Endorsed Transactions on Scalable Information Systems.")])],-1),v={id:"iterated-clique-reduction-in-vertex-weighted-coloring-for-large-sparse-graphs",tabindex:"-1"},w=e("a",{class:"header-anchor",href:"#iterated-clique-reduction-in-vertex-weighted-coloring-for-large-sparse-graphs","aria-hidden":"true"},"#",-1),I=e("div",{style:{"font-family":"Times New Roman",color:"black"}},[e("p",{style:{"text-align":"justify","font-family":"Times New Roman","font-size":"20px"}},[e("img",{src:h,align:"left",width:"110",heigh:"120",hspace:"5",vspace:"8",style:{"padding-top":"10px","padding-right":"10px"}}),n(),e("b",null,"Su Kaile,"),n(` Ph.D., Professor, currently work with Griffith University, who is an adjunct professor at the Logic Research Center of Tsinghua University, and the honorary dean of the School of Artificial Intelligence at Nanjing University of Information Science and Technology. His Main research areas include artificial intelligence logic and algorithms. He served as a professor and doctoral supervisor at Sun Yat-sen University (1999-2007) and Peking University (2007-2014). In 2007, he won the National Natural Science Foundation of China's "Outstanding Youth Fund" project, and in 2009, he was awarded the ARC Future Fellow of the Australian National Foundation. Won the AiML 2002 (Toulouse, France) Best Paper Award, SAT Challenge 2012: Best Sequential Solver (Random Track) Award. He has published more than 30 Category A papers recommended by the China Computing Society (CCF), including the top conference AAAI (15 papers) , IJCAI (10 articles), top journals Artificial Intelligence, Information and Computation, IEEE Trans. on Computers, and IEEE Trans. on Software Engineering, etc. `)])],-1);function C(S,x){const i=s("center");return r(),l("div",null,[m,e("h2",g,[y,n(),a(i,{style:{"font-family":"Times New Roman","font-size":"32px",color:"black","font-weight":"bold"}},{default:t(()=>[n("Challenges in Artificial Intelligence and Cybersecurity")]),_:1})]),p,e("h2",E,[A,n(),a(i,{style:{"font-family":"Times New Roman","font-size":"32px",color:"black","font-weight":"bold"}},{default:t(()=>[n("Evolutionary Framework for t-closeness Anonymization")]),_:1})]),b,e("h2",v,[w,n(),a(i,{style:{"font-family":"Times New Roman","font-size":"32px",color:"black","font-weight":"bold"}},{default:t(()=>[n("Iterated Clique Reduction in Vertex Weighted Coloring for Large Sparse Graphs")]),_:1})]),I])}const R=o(u,[["render",C],["__file","index.html.vue"]]);export{R as default};
